mapper.select:
SELECT mo.apt_cmplex_no       /*kr.or.ddit.domain.apt.mgmtOffice.partner.mapper.IPartnerMapper.selectAptCmplexNoByMgmtOfcNo*/
FROM mgmt_office mo
WHERE mo.mgmt_ofc_no = #{mgmtOfcNo}

mapper.sql:
WHERE p.apt_cmplex_no = #{aptCmplexNo}
AND p.biz_ty_nm = #{bizTyNm}
AND p.use_yn = #{useYn}
AND EXISTS ( SELECT 1 FROM facility_contract fc WHERE fc.partner_no = p.partner_no )
AND NOT EXISTS ( SELECT 1 FROM facility_contract fc WHERE fc.partner_no = p.partner_no )
AND EXISTS ( SELECT 1 FROM facility_check_hstry fch WHERE fch.partner_no = p.partner_no AND fch.chk_dt >= TO_DATE(#{checkStartDt}, 'yyyy-mm-dd') )
AND EXISTS ( SELECT 1 FROM facility_check_hstry fch WHERE fch.partner_no = p.partner_no AND fch.chk_dt < TO_DATE(#{checkEndDt}, 'yyyy-mm-dd') + 1 )
AND EXISTS ( SELECT 1 FROM utility_provider up JOIN meter_hstry mh ON mh.utility_provider_no = up.utility_provider_no WHERE up.partner_no = p.partner_no AND mh.meter_dt >= TO_DATE(#{meterStartDt}, 'yyyy-mm-dd') )
AND EXISTS ( SELECT 1 FROM utility_provider up JOIN meter_hstry mh ON mh.utility_provider_no = up.utility_provider_no WHERE up.partner_no = p.partner_no AND mh.meter_dt < TO_DATE(#{meterEndDt}, 'yyyy-mm-dd') + 1 )
AND ( LOWER(p.partner_no) LIKE '%' || LOWER(#{searchWord}) || '%' OR LOWER(p.partner_nm) LIKE '%' || LOWER(#{searchWord}) || '%' OR LOWER(p.pic_nm) LIKE '%' || LOWER(#{searchWord}) || '%' OR LOWER(p.pic_telno) LIKE '%' || LOWER(#{searchWord}) || '%' OR LOWER(p.bizrno) LIKE '%' || LOWER(#{searchWord}) || '%' )

mapper.insert:
INSERT INTO partner (      /*kr.or.ddit.domain.apt.mgmtOffice.partner.mapper.IPartnerMapper.insertPartner*/
                      partner_no
                    ,apt_cmplex_no
                    ,biz_ty_nm
                    ,partner_nm
                    ,bizrno
                    ,use_yn
                    ,pic_nm
                    ,pic_telno
                    ,pic_email
                    ,reg_dt
) VALUES (
           'PTR' || LPAD(seq_partner.nextval, 4, '0')
         ,#{aptCmplexNo}
         ,#{bizTyNm}
         ,#{partnerNm}
         ,#{bizrno}
         ,NVL(#{useYn}, 'Y')
         ,#{picNm}
         ,#{picTelno}
         ,#{picEmail}
         ,SYSDATE
         )

mapper.update:
UPDATE partner      /*kr.or.ddit.domain.apt.mgmtOffice.partner.mapper.IPartnerMapper.updatePartner*/
SET biz_ty_nm = #{bizTyNm}
  ,partner_nm = #{partnerNm}
  ,use_yn = NVL(#{useYn}, 'Y')
  ,pic_nm = #{picNm}
  ,pic_telno = #{picTelno}
  ,pic_email = #{picEmail}
  ,mdf_dt = SYSDATE
WHERE partner_no = #{partnerNo}
  AND apt_cmplex_no = #{aptCmplexNo}

UPDATE partner      /*kr.or.ddit.domain.apt.mgmtOffice.partner.mapper.IPartnerMapper.deactivatePartner*/
SET use_yn = 'N'
  ,mdf_dt = SYSDATE
WHERE partner_no = #{partnerNo}
  AND apt_cmplex_no = #{aptCmplexNo}

UPDATE partner      /*kr.or.ddit.domain.apt.mgmtOffice.partner.mapper.IPartnerMapper.activatePartner*/
SET use_yn = 'Y'
  ,mdf_dt = SYSDATE
WHERE partner_no = #{partnerNo}
  AND apt_cmplex_no = #{aptCmplexNo}
